<?php
namespace Database\Seeders;
use App\Models\Item;use App\Models\RefinementLevel;use App\Models\RefinementLevelMaterial;use Illuminate\Database\Seeder;use Illuminate\Support\Facades\DB;use RuntimeException;
class ItemRefinementTestingSeeder extends Seeder {public function run(){if(app()->environment()!=='testing'||substr((string)DB::connection()->getDatabaseName(),-8)!=='_testing')throw new RuntimeException('ItemRefinementTestingSeeder requires an isolated _testing database.');$iron=Item::updateOrCreate(['code'=>'refinement_iron_ore'],['name'=>'Mineral de hierro de refinamiento','description'=>'Material provisional de testing. Balance pendiente.','item_type'=>'material','equipment_type'=>null,'rarity'=>'common','is_stackable'=>true,'max_stack'=>99,'status'=>'active']);$coal=Item::updateOrCreate(['code'=>'refinement_coal'],['name'=>'Carbón de refinamiento','description'=>'Material provisional de testing. Balance pendiente.','item_type'=>'material','equipment_type'=>null,'rarity'=>'common','is_stackable'=>true,'max_stack'=>99,'status'=>'active']);$rules=[[0,1,10,[[$iron,2]]],[1,2,25,[[$iron,3],[$coal,1]]]];foreach($rules as $config){$rule=RefinementLevel::updateOrCreate(['from_level'=>$config[0]],['to_level'=>$config[1],'success_chance_basis_points'=>10000,'gold_cost'=>$config[2],'failure_behavior'=>'keep_level','status'=>'active']);foreach($config[3] as $material)RefinementLevelMaterial::updateOrCreate(['refinement_level_id'=>$rule->id,'item_id'=>$material[0]->id],['quantity'=>$material[1]]);}}}
